import React, { useState } from 'react';
import AppLayout from '../components/shared/AppLayout';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';
import toast from 'react-hot-toast';
import { format } from 'date-fns';

const plans = [
  {
    id: 'monthly',
    name: 'Monthly',
    price: '£9.99',
    period: '/month',
    description: 'Flexible — cancel anytime',
    features: [
      'Track up to 5 scores',
      'Monthly draw entry',
      'Charity contribution',
      'Win prizes',
    ],
    highlight: false,
  },
  {
    id: 'yearly',
    name: 'Yearly',
    price: '£89.99',
    period: '/year',
    description: 'Save 25% vs monthly',
    features: [
      'Everything in Monthly',
      '2 months free',
      'Priority draw entry',
      'Charity contribution',
    ],
    highlight: true,
    badge: 'Best Value',
  },
];

export default function SubscriptionPage() {
  const { user, refreshUser } = useAuth();
  const [loading, setLoading] = useState(null);

  const handleSubscribe = async (plan) => {
    setLoading(plan);
    try {
      await api.post('/users/subscribe', { plan });
      await refreshUser();
      toast.success(`🎉 Welcome to the ${plan} plan!`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Subscription failed');
    } finally {
      setLoading(null);
    }
  };

  const handleCancel = async () => {
    if (!window.confirm('Are you sure you want to cancel your subscription?')) return;
    setLoading('cancel');
    try {
      await api.post('/users/cancel-subscription');
      await refreshUser();
      toast.success('Subscription cancelled');
    } catch {
      toast.error('Failed to cancel subscription');
    } finally {
      setLoading(null);
    }
  };

  const isActive = user?.subscription_status === 'active';

  return (
    <AppLayout>
      <div className="max-w-3xl mx-auto space-y-8 animate-slide-up">
        <div>
          <h1 className="page-title">Subscription</h1>
          <p className="text-charcoal-400 mt-1">Choose a plan that works for you. Every subscription supports your chosen charity.</p>
        </div>

        {/* Current Status */}
        {isActive && (
          <div className="card border border-forest-800/40 bg-forest-900/10">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="badge-active">
                    <span className="w-2 h-2 rounded-full bg-forest-500 animate-pulse-slow" />
                    Active
                  </span>
                </div>
                <h3 className="font-display font-bold text-white text-lg capitalize">{user.plan} Plan</h3>
                {user.subscription_end && (
                  <p className="text-sm text-charcoal-400 mt-0.5">
                    Renews {format(new Date(user.subscription_end), 'MMMM d, yyyy')}
                  </p>
                )}
              </div>
              <button
                onClick={handleCancel}
                disabled={loading === 'cancel'}
                className="btn-danger"
              >
                {loading === 'cancel' ? 'Cancelling...' : 'Cancel Subscription'}
              </button>
            </div>
          </div>
        )}

        {/* Plans */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {plans.map(plan => {
            const isCurrent = isActive && user.plan === plan.id;
            return (
              <div
                key={plan.id}
                className={`relative rounded-2xl border p-7 transition-all duration-300 ${
                  plan.highlight
                    ? 'border-gold-700/60 bg-gradient-to-b from-gold-900/20 to-charcoal-900/60'
                    : 'border-charcoal-800 bg-charcoal-900/40'
                } ${isCurrent ? 'ring-2 ring-forest-600' : ''}`}
              >
                {plan.badge && (
                  <div className="absolute -top-3 left-1/2 -translate-x-1/2">
                    <span className="badge-gold">{plan.badge}</span>
                  </div>
                )}
                {isCurrent && (
                  <div className="absolute -top-3 right-6">
                    <span className="badge-active">Current Plan</span>
                  </div>
                )}

                <h3 className="font-display text-xl font-bold text-white mb-1">{plan.name}</h3>
                <p className="text-charcoal-500 text-sm mb-4">{plan.description}</p>

                <div className="flex items-end gap-1 mb-6">
                  <span className="font-display text-4xl font-bold text-white">{plan.price}</span>
                  <span className="text-charcoal-400 text-sm mb-1">{plan.period}</span>
                </div>

                <ul className="space-y-2.5 mb-7">
                  {plan.features.map((f, i) => (
                    <li key={i} className="flex items-center gap-2.5 text-sm text-charcoal-300">
                      <span className="text-forest-500 shrink-0">✓</span>
                      {f}
                    </li>
                  ))}
                </ul>

                <button
                  onClick={() => handleSubscribe(plan.id)}
                  disabled={!!loading || isCurrent}
                  className={`w-full ${plan.highlight ? 'btn-gold' : 'btn-primary'} ${isCurrent ? 'opacity-60 cursor-not-allowed' : ''}`}
                >
                  {loading === plan.id
                    ? 'Processing...'
                    : isCurrent
                    ? '✓ Current Plan'
                    : isActive
                    ? `Switch to ${plan.name}`
                    : `Start ${plan.name}`}
                </button>
              </div>
            );
          })}
        </div>

        {/* Mock payment notice */}
        <div className="p-4 rounded-xl bg-charcoal-800/30 border border-charcoal-700/40">
          <p className="text-xs text-charcoal-500 text-center">
            ⚠️ This is a simulated subscription system. No real payment is processed.
          </p>
        </div>
      </div>
    </AppLayout>
  );
}
